var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"으윽!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃呃！?"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"서윤!!","JPN":"シズカ！！","ENG":"Seo Yoon!","TWN":"徐芸！！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"선배, 서윤을 부탁할게! 레이 선배는 내가……!","JPN":"先輩、シズカは任せたよ！　レイ先輩は私が……！","ENG":"Shiyoon, take care of Seo Yoon! I'll...","TWN":"前輩，麻煩照顧好徐芸！雷伊前輩……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"막을 테니까!","JPN":"止めてみせるから！","ENG":"I'll take care of Ray!","TWN":"我去阻止！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"막기 위한 방법은 정해져 있어요, 유미나님.","JPN":"止めるための方法は定められています。","ENG":"There's only one way to do that, Yoo Mina.","TWN":"阻止的方法已經決定好了，劉米娜。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"동료 분들이 당하기 전에… 저를 죽이면 됩니다.","JPN":"仲間の皆さんがやられる前に……僕を殺してください。","ENG":"You kill me... before I kill them.","TWN":"在你的同伴被殺之前……殺死我就好。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"큭……!","JPN":"くっ……！","ENG":"Khhk...!","TWN":"唔……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"왜 그러시죠? 저는 기회를 드리고 있어요.","JPN":"どうしたんですか？　僕はチャンスをさしあげているんです。","ENG":"What's wrong? This is a chance.","TWN":"為什麼那種反應？我是在給你機會。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"세상을 구한 영웅이 될 수 있는 기회를.","JPN":"世界を救う英雄になれるチャンスを。","ENG":"A chance to become the hero who saves this world.","TWN":"成為拯救世界的英雄的機會。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_B","text":{"KOREA":"모른다고 하진 마세요. 유미나님은 거짓말을 하면 표정에 그대로 드러나거든요.","JPN":"知らないふりはやめてください。あなたは嘘をつくと顔に出ますから。","ENG":"Don't tell me you don't know what I'm talking about. It shows when you’re lying.","TWN":"你別說你不知道。劉米娜說謊時，從臉上就能看出來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAY_SCHOOL_NPC_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그딴 건……!","JPN":"そんなもの……！","ENG":"That...","TWN":"那種……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"그딴 기회는 벌써 예전에 버렸어!","JPN":"そんなチャンスなんてとっくの昔に捨ててる！","ENG":"I don’t need that kind of chance anymore!","TWN":"那種機會，我很早以前就放棄了！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"하아…… 하……","JPN":"はあ……はぁ……","ENG":"*Huff...* *Huff...*","TWN":"哈啊……哈……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"급소는 간발의 차로 빗나갔네요. 불행 중 다행이라고 말해도 될까요?","JPN":"急所は間一髪で逸れましたね。不幸中の幸いと言いましょうか？","ENG":"It was this close to hitting your artery. That's one good news, at least.","TWN":"以些許偏差錯開了要害。該說這是不幸中的萬幸嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"글쎄, 별로 기쁘진 않은걸. 부상 때문에 짐짝 신세가 되게 생겼잖아.","JPN":"さあね、あまり嬉しくはないかな。怪我のせいで足手まといになるから。","ENG":"Well, I'm not that glad. I'm now a burden, thanks to this injury.","TWN":"這個嘛，我倒是高興不起來。這個傷口，讓我變成累贅了不是嘛。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"하하. 역시 상황 파악 능력이 무척 뛰어나시네요, 서윤 양.","JPN":"ハハ。さすがの状況把握力ですね、シズカさん。","ENG":"Ha ha. You really are talented at reading the room, Seo Yoon.","TWN":"哈哈，你把掌握情況的能力果然很強啊，徐芸。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"칫…….","JPN":"ちぇっ……","ENG":"Tch...","TWN":"嘖……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"접근하는 게 눈에 보이지도 않았어……. 확실히 마왕답긴 하네.","JPN":"接近してきたのも見えなかった……これが魔王なのね。","ENG":"I didn't even see him approaching me... Guess he is the Demon Lord, after all.","TWN":"看不清靠近的動作呢……不愧是魔王。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"글쎄요. 그렇다기에는 검을 통해 전해지는 위력은 환각 속에서 느꼈던 것과 비슷하더군요.","JPN":"さあ。それにしては剣から感じられる威力は幻覚の中で感じたものと大差ありませんでしたよ。","ENG":"I’m not sure. The power I felt wasn't much different from what I felt in the hallucination.","TWN":"不好說呢。從劍上傳遞過來的力量和在幻覺中感受到的差不多。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그럼…… 아직 마왕의 힘은 쓰지도 않았다는 거야?","JPN":"じゃあ……まだ魔王の力は使ってもいないってこと？","ENG":"Then... are you saying we haven’t even seen his Demonic powers yet?","TWN":"那……也就是說，他還沒有使用魔王的力量嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"무작정 날뛰다 자칫 미나 양이 휘말려서 죽기라도 하면 저 분도 곤란하지 않겠어요?","JPN":"思いっきり暴れた拍子に、間違ってミナさんが巻き込まれて死にでもしたら、あちらも困るでしょうからね。","ENG":"If Mina gets caught up in the fight and dies, it would be an inconvenience to him as well.","TWN":"要是不小心把米娜也殺掉的話，他應該也會很為難吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"죽고 싶다는 분께서 그런 도박을 할 가능성은 희박할 것 같군요.","JPN":"死にたがっている方が、そんな賭けのような戦い方をするとは思えません。","ENG":"I don't think he's one to take such a risk, especially when he wants to kill himself.","TWN":"想死之人做那種賭注的可能性似乎很小。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"큭…… 아주 멋대로네.","JPN":"クッ……自分勝手ね。","ENG":"Ngh... Such a selfish idiot.","TWN":"咳……真是，自私的笨蛋啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저런 목숨 아까운 줄 모르는 애한테 가만히 앉아서 당해 줄 수는 없지. 선배도 협력해 줘.","JPN":"あんな命の大切さもわからないような奴に、何もせずにやられてあげるわけにはいかない。先輩も協力して。","ENG":"I won't just sit here and let that ungrateful kid do whatever he wants. Help me out, Shiyoon.","TWN":"面對那種不惜命的傢伙，可不能坐以待斃。前輩來配合一下吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"음? 두 분을 화해하게 만들 무슨 뾰족한 수라도 떠오르셨나요?","JPN":"うん？　あのお二人を仲直りさせる秘策でもあるんでしょうか？","ENG":"Hmm? Any ideas on getting the two of them to make up?","TWN":"嗯？你想到什麼讓二位和好的辦法了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그럼. 아주 뾰족한 수지.","JPN":"ええ、あるの。とっておきのやつがね。","ENG":"Yup. A good one, in fact.","TWN":"當然，是個非常好的辦法。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"우리가 미나랑 같이 차원의 틈으로 뛰어들 때 기억나?","JPN":"私たちがミナと次元の狭間に飛び込んだときのことを覚えている？","ENG":"Remember when we ran into the dimensional gap with Mina?","TWN":"你還記得我們和米娜一起跳進次元縫隙的時候嗎？"},"stage":{"bg":"ROOFTOP","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"황태자님을 가로막았던 두 분 말이군요.","JPN":"皇太子様の前に立ちふさがったお二人ですね。","ENG":"Are you referring to the two people who stood in the Crown Prince's way?","TWN":"你說攔住皇太子的二個人啊。"},"stage":{"bg":"ROOFTOP","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그래. 그 작자의 반응으로 봐서는 보통 높으신 분들이 아니었거든.","JPN":"ええ。皇太子の反応からして、きっとものすごく高位の存在だと思うの。","ENG":"Yeah. Guessing from his reaction, they looked like some higher-up authorities.","TWN":"是的。從那傢伙的反應來看，那二個人的地位不是一般的高。"},"stage":{"bg":"ROOFTOP","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"그 괴물들이 눈여겨 볼 정도니까……","JPN":"そんな化け物じみた存在でもハッとするほどだから……","ENG":"If this is enough for those monsters to covet...","TWN":"既然是那些怪物都很關注的厲害武器……"},"stage":{"bg":"ROOFTOP","bgm":"BATTLE_BOSS_04","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SERAPEL_QLIPHOTH_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"저 자살 지망자에게도 맞추기만 한다면 효과가 있을 것 같지 않아?","JPN":"あの自殺志願者にも、当てさえすれば何かしらの効果はあるんじゃないかな？","ENG":"Don't you think it'll deal some damage to that suicidal brat?","TWN":"如果打中那個自殺犯，會不會有效果呢？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"으음, 뾰족한 수라는 게 설마…….","JPN":"うーん、とっておきの秘策というのはまさか……","ENG":"Umm, what you mean by good idea is...","TWN":"嗯，你說的好辦法難道是……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"맞아. 미스틸테인이야.","JPN":"そう。ミスティルテインよ。","ENG":"That's right. Misteltein.","TWN":"沒錯，米斯特丁。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"BATTLE_BOSS_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};